// src/components/AddMember.jsx
import React, { useState } from 'react';
import { addMember } from '../services/api';

function AddMember({ onMemberAdded }) {
  const [formData, setFormData] = useState({
    nom: '',
    prenom: '',
    age: '',
    adresse: '',
    telephone: '',
    email: '',
    date_inscription: new Date().toISOString().split('T')[0], // تاريخ اليوم افتراضيًا
    type_membre: 'Adulte',
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccess(false);

    try {
      await addMember(formData);
      setSuccess(true);
      setFormData({
        nom: '',
        prenom: '',
        age: '',
        adresse: '',
        telephone: '',
        email: '',
        date_inscription: new Date().toISOString().split('T')[0],
        type_membre: 'Adulte',
      });

      // إعادة تحميل القائمة في الصفحة الأب (إذا أعطيتي callback)
      if (onMemberAdded) onMemberAdded();
    } catch (err) {
      setError(err.response?.data?.error || 'حدث خطأ أثناء إضافة العضو');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="card mb-4">
      <div className="card-header bg-primary text-white">
        <h5 className="mb-0">إضافة عضو جديد</h5>
      </div>
      <div className="card-body">
        {success && (
          <div className="alert alert-success">
            تم إضافة العضو بنجاح !
          </div>
        )}

        {error && (
          <div className="alert alert-danger">{error}</div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="row g-3">
            <div className="col-md-6">
              <label className="form-label">الاسم</label>
              <input
                type="text"
                name="nom"
                className="form-control"
                value={formData.nom}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-6">
              <label className="form-label">اللقب</label>
              <input
                type="text"
                name="prenom"
                className="form-control"
                value={formData.prenom}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-4">
              <label className="form-label">العمر</label>
              <input
                type="number"
                name="age"
                className="form-control"
                value={formData.age}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-8">
              <label className="form-label">البريد الإلكتروني</label>
              <input
                type="email"
                name="email"
                className="form-control"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-6">
              <label className="form-label">رقم الهاتف</label>
              <input
                type="tel"
                name="telephone"
                className="form-control"
                value={formData.telephone}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-6">
              <label className="form-label">العنوان</label>
              <input
                type="text"
                name="adresse"
                className="form-control"
                value={formData.adresse}
                onChange={handleChange}
              />
            </div>

            <div className="col-md-6">
              <label className="form-label">تاريخ التسجيل</label>
              <input
                type="date"
                name="date_inscription"
                className="form-control"
                value={formData.date_inscription}
                onChange={handleChange}
                required
              />
            </div>

            <div className="col-md-6">
              <label className="form-label">نوع العضوية</label>
              <select
                name="type_membre"
                className="form-select"
                value={formData.type_membre}
                onChange={handleChange}
                required
              >
                <option value="Adulte">بالغ</option>
                <option value="Enfant">طفل</option>
              </select>
            </div>
          </div>

          <div className="mt-4">
            <button
              type="submit"
              className="btn btn-success"
              disabled={loading}
            >
              {loading ? 'جاري الإضافة...' : 'إضافة العضو'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default AddMember;
